const KEY = "slate_watch_history";
const MAX_ITEMS = 20;

export interface WatchEntry {
  id: number;
  type: "movie" | "tv";
  title: string;
  posterPath: string | null;
  watchedAt: number; // Date.now()
  progress?: number; // 0–1
}

export function getWatchHistory(): WatchEntry[] {
  if (typeof window === "undefined") return [];
  try {
    return JSON.parse(localStorage.getItem(KEY) || "[]");
  } catch {
    return [];
  }
}

export function addToWatchHistory(entry: Omit<WatchEntry, "watchedAt">) {
  if (typeof window === "undefined") return;
  const history = getWatchHistory().filter((e) => !(e.id === entry.id && e.type === entry.type));
  history.unshift({ ...entry, watchedAt: Date.now() });
  localStorage.setItem(KEY, JSON.stringify(history.slice(0, MAX_ITEMS)));
}

export function removeFromWatchHistory(id: number, type: "movie" | "tv") {
  if (typeof window === "undefined") return;
  const history = getWatchHistory().filter((e) => !(e.id === id && e.type === type));
  localStorage.setItem(KEY, JSON.stringify(history));
}

export function updateWatchProgress(id: number, type: "movie" | "tv", progress: number) {
  if (typeof window === "undefined") return;
  const history = getWatchHistory();
  const idx = history.findIndex((e) => e.id === id && e.type === type);
  if (idx === -1) return;
  history[idx].progress = progress;
  localStorage.setItem(KEY, JSON.stringify(history));
}
